/**
 * @fileoverview InfiniteScroll state — reactive state wiring.
 * @module module/InfiniteScroll/state
 */

/**
 * Create reactive InfiniteScroll state.
 *
 * Tracks `page`, `loading`, and `hasMore` as observable properties
 * so external consumers can react to changes.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @param {object} initial — { page, loading, hasMore }
 * @returns {{ ref: object, setState: Function }}
 */
export function createReactiveState(stateFn, initial = {}) {
    const [ref, setState] = stateFn({
        page:    initial.page    ?? 0,
        loading: initial.loading ?? false,
        hasMore: initial.hasMore ?? true,
    });
    return { ref, setState };
}

/**
 * Push current internal state into the reactive store.
 *
 * @param {Function} setState — reactive setter
 * @param {object} vals — { page, loading, hasMore }
 */
export function syncState(setState, vals) {
    setState({
        page:    vals.page,
        loading: vals.loading,
        hasMore: vals.hasMore,
    });
}
