/**
 * @fileoverview InfiniteScroll view — sentinel DOM build / teardown + state display.
 * @module module/InfiniteScroll/view
 */

import razyui from '../../index.js';
import { CLS, DEFAULT_SPINNER_HTML, SENTINEL_SPELL, SPINNER_SPELL, PART } from './constants.js';
import { setContent } from '../shared/setContent.js';

// ═══════════════════════════════════════
//  Sentinel DOM
// ═══════════════════════════════════════

/**
 * Build the sentinel element (spinner + end-message + error/retry).
 *
 * @param {Function} spell — razyui.spell DOM helper
 * @param {object} config — component config
 * @returns {HTMLElement} the sentinel root element
 */
export function buildSentinel(spell, config) {
    const dom = spell(SENTINEL_SPELL, true);
    const s   = dom[0];
    PART.SENTINEL.apply(dom);

    // Spinner (conditional)
    if (config.spinner) {
        const spin = spell(SPINNER_SPELL, true);
        if (config.spinnerHTML) {
            setContent(spin, config.spinnerHTML);
        } else {
            spin.html(DEFAULT_SPINNER_HTML);
        }
        PART.SPINNER.apply(spin);
        // Apply to each dot inside the spinner
        spin.find('.' + CLS.DOT).each(function () {
            PART.DOT.apply(this);
        });
        dom.prepend(spin);
    }

    // End message
    const $end = dom.find('.is-end');
    $end.text(config.endMessage);
    PART.END.apply($end);

    // Error / retry
    const $err = dom.find('.is-error');
    $err.text(config.errorMessage);
    PART.ERROR.apply($err);

    return s;
}

/**
 * Insert the sentinel as the last child of the given parent.
 *
 * @param {HTMLElement} sentinel
 * @param {HTMLElement|null} container
 * @param {HTMLElement|null} contentEl
 */
export function insertSentinel(sentinel, container, contentEl) {
    const parent = container || contentEl;
    if (parent) {
        razyui(parent).append(sentinel);
    } else {
        razyui(document.body).append(sentinel);
    }
}

/**
 * Update sentinel CSS classes to reflect current state flags.
 *
 * @param {HTMLElement|null} sentinel
 * @param {boolean} loading
 * @param {boolean} hasMore
 * @param {boolean} error
 */
export function updateSentinelState(sentinel, loading, hasMore, error) {
    if (!sentinel) return;
    const $s = razyui(sentinel);
    $s.toggleClass(CLS.LOADING,     loading)
      .toggleClass(CLS.DONE,        !hasMore && !error)
      .toggleClass(CLS.ERROR_STATE, error)
      .toggleClass(CLS.IDLE,        !loading && hasMore && !error);
}

/**
 * Move sentinel to the last-child position (user's onLoad
 * may have appended content after it).
 *
 * @param {HTMLElement|null} sentinel
 */
export function keepSentinelLast(sentinel) {
    if (!sentinel) return;
    const parent = sentinel.parentNode;
    if (parent && parent.lastElementChild !== sentinel) {
        razyui(parent).append(sentinel);
    }
}

/**
 * Remove the sentinel from the DOM.
 *
 * @param {HTMLElement|null} sentinel
 */
export function removeSentinel(sentinel) {
    if (sentinel && sentinel.parentNode) {
        razyui(sentinel).remove();
    }
}
